import Foundation
import CryptoKit
import BlockchainKit

class CryptoWallet {

    private var privateKey: PrivateKey
    private var blockchain: Blockchain

    init() {
        // Generate a new private key
        self.privateKey = try! ECPrivateKey(curve: .secp256k1)

        // Initialize the blockchain connection
        self.blockchain = Blockchain(network: .mainNet)
    }

    // Generate a new wallet address
    func generateAddress() -> String {
        let publicKey = privateKey.publicKey
        let address = blockchain.address(from: publicKey)
        return address
    }

    // Sign a transaction
    func signTransaction(transaction: Transaction) -> Transaction {
        let signature = try! blockchain.sign(transaction: transaction, privateKey: privateKey)
        transaction.signature = signature
        return transaction
    }

    // Send a transaction
    func sendTransaction(transaction: Transaction) {
        blockchain.broadcast(transaction: transaction)
    }
}